       std::vector<std::string> s = Rcpp::as<std::vector<std::string> >(ss);

    return Rcpp::wrap(Rcpp::DataFrame::create(Rcpp::Named("input") = s,
                                   Rcpp::Named("valid") = valid,
                                   Rcpp::Named("machine") = machine,
                                   Rcpp::Named("human") = human));

